import sys, json
data = json.load(sys.stdin)
items = data['items']
print(f'total items: {len(items)}')
print()
issues = []
for c in items:
    cid = c['conflict_id']
    for side in ('candidate_a','candidate_b'):
        cand = c.get(side)
        if cand is None:
            issues.append((cid, f'{side} is None'))
            continue
        srcs = cand.get('sources')
        if srcs is None:
            issues.append((cid, f'{side}.sources is None'))
            continue
        if not isinstance(srcs, list):
            issues.append((cid, f'{side}.sources not a list: {type(srcs).__name__}'))
            continue
        for i, s in enumerate(srcs):
            if s is None:
                issues.append((cid, f'{side}.sources[{i}] is None'))
            elif 'authority' not in s:
                issues.append((cid, f'{side}.sources[{i}] missing authority. keys={list(s.keys())}'))
            elif s['authority'] is None:
                issues.append((cid, f'{side}.sources[{i}].authority is null. doc={s.get(\"document_path\")}'))
print(f'issues: {len(issues)}')
for i in issues[:20]:
    print(' ', i)
print()
print('sample conflict_types:', set(c['conflict_type'] for c in items))
print('sample missing-candidate cases:')
for c in items[:50]:
    if c.get('candidate_a') is None or c.get('candidate_b') is None:
        print(' ', c['conflict_id'], c['conflict_type'], 'a?', c.get('candidate_a') is not None, 'b?', c.get('candidate_b') is not None)
"

