            rows = list(
                conn.execute(
                    """
                    SELECT e.id, e.name, e.type, d.degree
                    FROM (
                        SELECT subject_id AS id, COUNT(*) AS degree
                        FROM triples WHERE status='active' GROUP BY subject_id
                    ) d
                    JOIN entities e ON e.id = d.id
                    WHERE e.status='active'
